{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"none","dataSources":[{"sourceType":"datasetVersion","sourceId":15024217,"datasetId":9616903,"databundleVersionId":15901911}],"dockerImageVersionId":31286,"isInternetEnabled":true,"language":"python","sourceType":"script","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"# %% [code]\n#!/usr/bin/env python3\n\"\"\"\nite_chatbot_kaggle.py\n\nITE Law Chatbot — mT5 + Hybrid Retrieval (Kaggle environment)\n\nArchitecture:\n  User question\n       ↓\n  IntentAwareRetriever  (build_index_hybrid_v3 + intent_aware_retriever)\n  → retrieves top-k Pasal + Penjelasan chunks\n       ↓\n  mT5 fine-tuned reader\n  → generates a natural Indonesian answer from retrieved context\n       ↓\n  Print answer\n\nSetup (run these as separate cells in Kaggle):\n  - Add your trained model as a Kaggle Dataset (mt5_ite_best/)\n  - Add your index as a Kaggle Dataset (index_v3/)\n  - Add your raw JSONL files as a Kaggle Dataset (if rebuilding index)\n  - Add build_index_hybrid_v3.py and intent_aware_retriever.py as utility scripts\n\nKaggle dataset paths follow: /kaggle/input/<dataset-slug>/<file>\n\"\"\"\n\n# =============================================================================\n# CELL 1 — Install dependencies\n# =============================================================================\n# Run this cell once. Kaggle already has torch/transformers, but we need a\n# few extras.\n\nimport subprocess\nsubprocess.run([\n    \"pip\", \"install\", \"-q\",\n    \"faiss-cpu\",        # or faiss-gpu if you have GPU session\n    \"rank_bm25\",\n    \"sentence-transformers\",\n    \"sentencepiece\",\n], check=True)\n\nprint(\"Dependencies installed.\")\n\n\n# =============================================================================\n# CELL 2 — Configuration\n# =============================================================================\n\nimport os\n\n# ── Paths ─────────────────────────────────────────────────────────────────────\n# Adjust these slugs to match your actual Kaggle dataset names.\n\n# Your fine-tuned mT5 model (output of the training notebook)\nMT5_MODEL_DIR = \"/kaggle/input/optimus/mt5_ite_best\"\n\n# Your built hybrid index (output of build_index_hybrid_v3.py build command)\n# If you haven't built it yet, see CELL 3b below.\nINDEX_DIR = \"/kaggle/input/optimus/index_v3\"\n\n# Raw JSONL files — only needed if you want to rebuild the index in this notebook\nPASAL_JSONL    = \"/kaggle/input/ite-law-data/pasal_master.jsonl\"\nPENJELASAN_JSONL = \"/kaggle/input/ite-law-data/penjelasan_master.jsonl\"\n\n# Utility scripts — add these as Kaggle utility scripts or copy them inline\nSCRIPTS_DIR = \"/kaggle/input/ite-scripts\"   # where you uploaded the .py files\n\n# ── Generation config ─────────────────────────────────────────────────────────\nMAX_INPUT_LEN  = 512\nMAX_TARGET_LEN = 256\nNUM_BEAMS      = 4      # beam search — higher = better quality, slower\nTOP_K_PASAL    = 3      # how many Pasal chunks to retrieve\nTOP_K_PENJ     = 2      # how many Penjelasan chunks per Pasal\n\n\n# =============================================================================\n# CELL 3a — (If you have a pre-built index) Load the retriever\n# =============================================================================\n# Copy the utility scripts into the working directory so they can be imported.\n\nimport sys\nimport shutil\n\n# Make scripts importable\nfor fname in [\"build_index_hybrid_v3.py\", \"intent_aware_retriever.py\"]:\n    src = os.path.join(SCRIPTS_DIR, fname)\n    dst = os.path.join(\"/kaggle/working\", fname)\n    if os.path.exists(src):\n        shutil.copy(src, dst)\n    else:\n        raise FileNotFoundError(\n            f\"Script not found: {src}\\n\"\n            \"Upload build_index_hybrid_v3.py and intent_aware_retriever.py \"\n            \"as a Kaggle Dataset and set SCRIPTS_DIR correctly.\"\n        )\n\nsys.path.insert(0, \"/kaggle/working\")\n\nfrom intent_aware_retriever import IntentAwareRetriever\nfrom pathlib import Path\n\nprint(\"Loading retriever index...\")\nretriever = IntentAwareRetriever.load(Path(INDEX_DIR))\nprint(f\"Retriever ready. {len(retriever.documents)} documents loaded.\")\n\n\n# =============================================================================\n# CELL 3b — (OPTIONAL) Build the index fresh if you don't have one yet\n# =============================================================================\n# Skip this cell if you already have a pre-built index uploaded as a dataset.\n\ndef build_index_if_needed(pasal_path, penjelasan_path, out_dir=\"/kaggle/working/index_v3\"):\n    \"\"\"\n    Builds and saves the hybrid index to /kaggle/working/index_v3.\n    Run once, then download the folder and upload it as a Kaggle Dataset\n    so you don't have to rebuild every session.\n    \"\"\"\n    from build_index_hybrid_v3 import HybridRetriever\n    from pathlib import Path\n\n    out = Path(out_dir)\n    if out.exists() and (out / \"metadata.json\").exists():\n        print(f\"Index already exists at {out_dir}, skipping build.\")\n        return out_dir\n\n    print(\"Building hybrid index (this takes ~5-10 min on Kaggle)...\")\n    r = HybridRetriever()\n    r.load_from_jsonl([Path(pasal_path), Path(penjelasan_path)])\n    r.build_all_indices()\n    r.save(out)\n    print(f\"Index saved to {out_dir}\")\n    print(\"Download this folder and upload it as a Kaggle Dataset for next time.\")\n    return out_dir\n\n# Uncomment to run:\n# INDEX_DIR = build_index_if_needed(PASAL_JSONL, PENJELASAN_JSONL)\n# retriever = IntentAwareRetriever.load(Path(INDEX_DIR))\n\n\n# =============================================================================\n# CELL 4 — Load the fine-tuned mT5 model\n# =============================================================================\n\nimport torch\nfrom transformers import AutoTokenizer, AutoModelForSeq2SeqLM\n\ndevice = \"cuda\" if torch.cuda.is_available() else \"cpu\"\nprint(f\"Using device: {device}\")\n\nprint(f\"Loading mT5 from {MT5_MODEL_DIR}...\")\ntokenizer = AutoTokenizer.from_pretrained(MT5_MODEL_DIR)\nmodel     = AutoModelForSeq2SeqLM.from_pretrained(MT5_MODEL_DIR).to(device)\nmodel.eval()\nprint(\"mT5 model ready.\")\n\n\n# =============================================================================\n# CELL 5 — Core generation functions\n# =============================================================================\n\ndef build_mt5_input(question: str, pasal_results, penjelasan_results) -> str:\n    \"\"\"\n    Packs question + retrieved context into the mT5 input format used during training.\n    Format: \"jawab pertanyaan: {Q} konteks: {pasal_text} [PENJELASAN] {penj_text}\"\n    \"\"\"\n    pasal_text = \"\"\n    if pasal_results:\n        pasal_text = pasal_results[0].document.text\n\n    penj_text = \"\"\n    if penjelasan_results:\n        penj_text = penjelasan_results[0].document.text\n\n    if penj_text:\n        context = f\"{pasal_text} [PENJELASAN] {penj_text}\"\n    else:\n        context = pasal_text\n\n    return f\"jawab pertanyaan: {question} konteks: {context}\"\n\n\ndef generate_answer(\n    question: str,\n    retriever,\n    model,\n    tokenizer,\n    device: str,\n    top_k_pasal: int = TOP_K_PASAL,\n    top_k_penj: int = TOP_K_PENJ,\n    num_beams: int = NUM_BEAMS,\n    verbose: bool = False,\n) -> dict:\n    \"\"\"\n    Full RAG pipeline: retrieve → generate.\n\n    Returns a dict with:\n        answer          - generated answer string\n        detected_intent - intent class\n        pasal_results   - retrieved Pasal chunks\n        penjelasan_results - retrieved Penjelasan chunks\n        mt5_input       - the packed input string (useful for debugging)\n    \"\"\"\n    # 1. Retrieve relevant legal chunks\n    retrieval = retriever.search_with_intent(\n        question,\n        top_k_pasal=top_k_pasal,\n        top_k_penjelasan_per_pasal=top_k_penj,\n    )\n\n    pasal_results = retrieval[\"pasal_results\"]\n    penjelasan_results = retrieval[\"penjelasan_results\"]\n    intent = retrieval[\"detected_intent\"]\n\n    # 2. Pack into mT5 input format\n    mt5_input = build_mt5_input(question, pasal_results, penjelasan_results)\n\n    if verbose:\n        print(f\"\\n[Intent: {intent}]\")\n        print(f\"[mT5 input ({len(mt5_input)} chars)]: {mt5_input[:300]}...\")\n\n    # 3. Tokenize\n    inputs = tokenizer(\n        mt5_input,\n        max_length=MAX_INPUT_LEN,\n        truncation=True,\n        return_tensors=\"pt\",\n    ).to(device)\n\n    # 4. Generate with beam search\n    with torch.no_grad():\n        output_ids = model.generate(\n            **inputs,\n            max_new_tokens=MAX_TARGET_LEN,\n            num_beams=num_beams,\n            early_stopping=True,\n            no_repeat_ngram_size=3,     # reduces repetition\n            length_penalty=1.0,\n        )\n\n    # 5. Decode\n    answer = tokenizer.decode(output_ids[0], skip_special_tokens=True).strip()\n\n    return {\n        \"answer\": answer,\n        \"detected_intent\": intent,\n        \"pasal_results\": pasal_results,\n        \"penjelasan_results\": penjelasan_results,\n        \"mt5_input\": mt5_input,\n    }\n\n\ndef format_sources(result: dict) -> str:\n    \"\"\"Pretty-print the source articles used for the answer.\"\"\"\n    lines = []\n    for res in result[\"pasal_results\"]:\n        doc = res.document\n        lines.append(f\"  [{doc.source} | Pasal {doc.pasal} Ayat {doc.ayat}] \"\n                     f\"(score: {res.score:.3f})\")\n    return \"\\n\".join(lines) if lines else \"  (tidak ada)\"\n\n\n# =============================================================================\n# CELL 6 — Interactive chatbot loop\n# =============================================================================\n\ndef run_chatbot(show_sources: bool = True, show_intent: bool = True, verbose: bool = False):\n    \"\"\"\n    Simple text chatbot loop for Kaggle notebook.\n    Type 'quit' or 'q' to exit.\n    \"\"\"\n    print(\"\\n\" + \"=\" * 70)\n    print(\"  Chatbot UU ITE — mT5 + Hybrid Retrieval\")\n    print(\"=\" * 70)\n    print(\"Tanyakan sesuatu tentang UU ITE (Bahasa Indonesia).\")\n    print(\"Ketik 'quit' untuk keluar.\\n\")\n\n    while True:\n        try:\n            question = input(\"Kamu: \").strip()\n        except (EOFError, KeyboardInterrupt):\n            print(\"\\nSelamat tinggal!\")\n            break\n\n        if not question:\n            continue\n        if question.lower() in (\"quit\", \"q\", \"exit\"):\n            print(\"Selamat tinggal!\")\n            break\n\n        result = generate_answer(\n            question,\n            retriever=retriever,\n            model=model,\n            tokenizer=tokenizer,\n            device=device,\n            verbose=verbose,\n        )\n\n        print(f\"\\nBot: {result['answer']}\")\n\n        if show_intent:\n            print(f\"  [Intent: {result['detected_intent']}]\")\n\n        if show_sources and result[\"pasal_results\"]:\n            print(f\"  Sumber:\")\n            print(format_sources(result))\n\n        print()\n\n\n# ── Run the chatbot ───────────────────────────────────────────────────────────\nrun_chatbot(show_sources=True, show_intent=True)\n\n\n# =============================================================================\n# CELL 7 — (Optional) Single-shot usage without the loop\n# =============================================================================\n# Use this for batch testing or if you want to call generate_answer() directly.\n\ndef demo_questions():\n    test_questions = [\n        \"Apa itu pencemaran nama baik menurut UU ITE?\",\n        \"Apa isi Pasal 27 ayat 3 dan sanksinya?\",\n        \"Berapa hukuman untuk penyebaran konten pornografi?\",\n        \"Bolehkah saya menyebarkan screenshot chat pribadi orang lain?\",\n        \"Bagaimana cara melaporkan kejahatan siber?\",\n    ]\n\n    print(\"\\n\" + \"=\" * 70)\n    print(\"DEMO — Single-shot questions\")\n    print(\"=\" * 70)\n\n    for q in test_questions:\n        print(f\"\\nQ: {q}\")\n        result = generate_answer(\n            q,\n            retriever=retriever,\n            model=model,\n            tokenizer=tokenizer,\n            device=device,\n        )\n        print(f\"A: {result['answer']}\")\n        print(f\"   [Intent: {result['detected_intent']}]\")\n        print(f\"   Sumber: {format_sources(result)}\")\n\n# Uncomment to run demo:\n# demo_questions()\n","metadata":{"_uuid":"96c2589a-5f0c-4b26-9020-5b69f4153c04","_cell_guid":"d46069fc-ccae-4d73-9379-7e51b3cc15dc","trusted":true,"collapsed":false,"jupyter":{"outputs_hidden":false},"execution":{"iopub.status.busy":"2026-03-03T04:37:18.393106Z","iopub.execute_input":"2026-03-03T04:37:18.393609Z","iopub.status.idle":"2026-03-03T04:37:27.374449Z","shell.execute_reply.started":"2026-03-03T04:37:18.393568Z","shell.execute_reply":"2026-03-03T04:37:27.372798Z"}},"outputs":[{"name":"stdout","text":"   ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ 23.8/23.8 MB 58.5 MB/s eta 0:00:00\nDependencies installed.\n","output_type":"stream"},{"traceback":["\u001b[0;31m---------------------------------------------------------------------------\u001b[0m","\u001b[0;31mFileNotFoundError\u001b[0m                         Traceback (most recent call last)","\u001b[0;32m/tmp/ipykernel_55/886428469.py\u001b[0m in \u001b[0;36m<cell line: 0>\u001b[0;34m()\u001b[0m\n\u001b[1;32m     90\u001b[0m         \u001b[0mshutil\u001b[0m\u001b[0;34m.\u001b[0m\u001b[0mcopy\u001b[0m\u001b[0;34m(\u001b[0m\u001b[0msrc\u001b[0m\u001b[0;34m,\u001b[0m \u001b[0mdst\u001b[0m\u001b[0;34m)\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[1;32m     91\u001b[0m     \u001b[0;32melse\u001b[0m\u001b[0;34m:\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[0;32m---> 92\u001b[0;31m         raise FileNotFoundError(\n\u001b[0m\u001b[1;32m     93\u001b[0m             \u001b[0;34mf\"Script not found: {src}\\n\"\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n\u001b[1;32m     94\u001b[0m             \u001b[0;34m\"Upload build_index_hybrid_v3.py and intent_aware_retriever.py \"\u001b[0m\u001b[0;34m\u001b[0m\u001b[0;34m\u001b[0m\u001b[0m\n","\u001b[0;31mFileNotFoundError\u001b[0m: Script not found: /kaggle/input/ite-scripts/build_index_hybrid_v3.py\nUpload build_index_hybrid_v3.py and intent_aware_retriever.py as a Kaggle Dataset and set SCRIPTS_DIR correctly."],"ename":"FileNotFoundError","evalue":"Script not found: /kaggle/input/ite-scripts/build_index_hybrid_v3.py\nUpload build_index_hybrid_v3.py and intent_aware_retriever.py as a Kaggle Dataset and set SCRIPTS_DIR correctly.","output_type":"error"}],"execution_count":1}]}